-- FR-9 example community runs (verifiable via the SearchPage 'Verify' button).
--
-- Derived from the owner's annotated traverse_api_input scenarios:
-- buildSimInputs -> Driver -> summarizeEngine over the committed real fixtures.
-- The forward sim advances waves on the MAX (1.1) roll (RunAdapter.MAX_ROLL);
-- damage_at_10 is the 1.0-baseline, per_enemy.damage_taken is at the 1.1 roll.
-- Idempotent on (quest_id, servant_collection_nos, np_levels); submit_run only
-- overwrites on a LOWER total_np_cost, so refreshing equal-cost rows needs a
-- DELETE first.
--
-- Excluded: the kazuradrop scenario (373/426/421/426 @ Kukulcan NP5). With the
-- corrected ATK + max-roll advancement its wave 1 now clears (181,593 > 181,138),
-- but it stops at wave 2 — Kazuradrop's class-change / sakura-series NP scaling
-- isn't fully modeled, so wave 2 under-clears. Re-add once that lands.

-- implantable stacking debuff (Roman SE, 2 waves) — quest 94089601, MC 20
SELECT public.submit_run(94089601, ARRAY[314,314,280,316]::integer[], ARRAY[1,1,1,1]::smallint[], 2::smallint, $tok$b3 c3 e3 f3 i a3 d3 6 # h i g j x11 a b3 c3 6 #$tok$, $j${"1":{"hp_required":340551,"damage_at_09":470371.12210617453,"damage_at_10":522634.5801179717,"damage_at_11":574898.0381297689,"outcome":"guaranteed","clear_probability":1,"min_multiplier_needed":0.6516044153127585,"per_enemy":[{"index":0,"name":"Imperial Guard A","max_hp":108137,"damage_taken":191632.67937658963,"np_refund":0},{"index":1,"name":"Imperial Guard B","max_hp":111176,"damage_taken":191632.67937658963,"np_refund":0},{"index":2,"name":"Imperial Guard C","max_hp":121238,"damage_taken":191632.67937658963,"np_refund":0}]},"2":{"hp_required":850256,"damage_at_09":1292138.5436819675,"damage_at_10":1435709.492979964,"damage_at_11":1579280.4422779605,"outcome":"guaranteed","clear_probability":1,"min_multiplier_needed":0.5922200864153969,"per_enemy":[{"index":0,"name":"Duo Duo Yi Shan Tank","max_hp":266626,"damage_taken":729648.3021392751,"np_refund":0},{"index":1,"name":"Lu Bu","max_hp":583630,"damage_taken":849632.1401386854,"np_refund":0}]}}$j$::jsonb, 20);

